pragma solidity 0.8.20;

contract CollectibleSale {
    address public owner;
    uint256 public maxSupply;
    uint256 public price;
    uint256 public totalMinted;
    bool public saleEnded;
    mapping(address => uint256) public balances;

    event Bought(address indexed buyer, uint256 amount);
    event PriceChanged(uint256 newPrice);
    event Withdrawn(address indexed owner, uint256 amount);

    error NotOwner();
    error SaleEnded();
    error InvalidAmount();
    error ExceedsMaxSupply();
    error IncorrectPayment();
    error TransferFailed();

    modifier onlyOwner() {
        if (msg.sender != owner) revert NotOwner();
        _;
    }

    modifier saleActive() {
        if (saleEnded) revert SaleEnded();
        _;
    }

    constructor(uint256 maxSupply_, uint256 price_) {
        owner = msg.sender;
        maxSupply = maxSupply_;
        price = price_;
    }

    function buy(uint256 amount) external payable saleActive {
        if (amount == 0 || amount > 10) revert InvalidAmount();
        if (totalMinted + amount > maxSupply) revert ExceedsMaxSupply();
        if (msg.value != amount * price) revert IncorrectPayment();

        balances[msg.sender] += amount;
        totalMinted += amount;

        if (totalMinted == maxSupply) {
            saleEnded = true;
        }

        emit Bought(msg.sender, amount);
    }

    function setPrice(uint256 newPrice) external onlyOwner {
        price = newPrice;
        emit PriceChanged(newPrice);
    }

    function withdraw() external onlyOwner {
        uint256 balance = address(this).balance;
        (bool success, ) = owner.call{value: balance}("");
        if (!success) revert TransferFailed();
        emit Withdrawn(owner, balance);
    }
}
